// Phase 2A generated-output verifier.
//
// Runs AFTER `astro build` (so `dist/` exists). Verifies that the prerendered
// data surface in `dist/` is byte-identical to the repository source, validates
// against the production contracts, and asserts that no Phase 2B browser runtime
// behavior or external runtime URL leaked into the build. Makes no network
// requests and never writes into source files.
//
// Node 22 strips TypeScript types on import, so the production `.ts` contracts
// are imported directly and exercised against the generated bytes.

import { readFileSync, existsSync, readdirSync } from "node:fs";
import { fileURLToPath } from "node:url";

import { assertSnapshot } from "../src/lib/public-surface-authority-map/contract.ts";
import {
  assertRuntimeManifest,
  assertManifestMatchesSnapshot,
  snapshotPathForId,
} from "../src/lib/public-surface-authority-map/runtimeManifestContract.ts";
import {
  sha256Hex,
  gitBlobSha1Hex,
} from "../src/lib/public-surface-authority-map/byteIdentity.ts";

const root = new URL("../", import.meta.url);
const p = (rel) => fileURLToPath(new URL(rel, root));

const APPROVED_SNAPSHOT_ID =
  "97631bc0a36f39331a6950d1498400213208afb6-82f7f74b98a9b3b94a9ed0b12a394f1db2d9b5d256f700d311061c1353f4ef1e";
const EXPECTED_BYTE_LENGTH = 83727;
const EXPECTED_SHA256 =
  "82f7f74b98a9b3b94a9ed0b12a394f1db2d9b5d256f700d311061c1353f4ef1e";
const EXPECTED_GIT_BLOB = "aa25de9c60b0c0bcb2f8fec1f82bafc135e1f10b";

const SRC_FALLBACK = p("src/data/public-surface-authority-map/last-known-good.json");
const SRC_SNAPSHOT = p(
  `src/data/public-surface-authority-map/runtime-snapshots/${APPROVED_SNAPSHOT_ID}.json`,
);
const SRC_MANIFEST = p("src/data/public-surface-authority-map/runtime-manifest.json");

const DIST_MANIFEST = p("dist/public-surface-map/data/manifest.json");
const DIST_SNAPSHOT = p(
  `dist/public-surface-map/data/snapshots/${APPROVED_SNAPSHOT_ID}.json`,
);
const DIST_HEADERS = p("dist/_headers");
const DIST_INTERACTIVE = p("dist/public-surface-map/interactive/index.html");
const DIST_ASTRO = p("dist/_astro");

const results = [];
let failed = 0;

async function check(name, fn) {
  try {
    const detail = await fn();
    results.push(`PASS  ${name}${detail ? ` — ${detail}` : ""}`);
  } catch (error) {
    failed += 1;
    results.push(`FAIL  ${name} — ${error.message}`);
  }
}

function readBytes(path) {
  return new Uint8Array(readFileSync(path));
}

function bytesEqual(a, b) {
  if (a.length !== b.length) return false;
  for (let i = 0; i < a.length; i += 1) if (a[i] !== b[i]) return false;
  return true;
}

function clientJsFiles() {
  if (!existsSync(DIST_ASTRO)) return [];
  return readdirSync(DIST_ASTRO)
    .filter((f) => f.endsWith(".js"))
    .map((f) => p(`dist/_astro/${f}`));
}

const srcSnapshotBytes = readBytes(SRC_SNAPSHOT);
const srcManifestBytes = readBytes(SRC_MANIFEST);
let manifest;

await check("01 generated manifest route exists", () => {
  if (!existsSync(DIST_MANIFEST)) throw new Error(`missing ${DIST_MANIFEST}`);
});

await check("02 generated snapshot route exists", () => {
  if (!existsSync(DIST_SNAPSHOT)) throw new Error(`missing ${DIST_SNAPSHOT}`);
});

await check("03 generated snapshot bytes == source snapshot bytes", () => {
  if (!bytesEqual(readBytes(DIST_SNAPSHOT), srcSnapshotBytes)) {
    throw new Error("byte mismatch");
  }
});

await check("04 generated manifest bytes == source manifest bytes", () => {
  if (!bytesEqual(readBytes(DIST_MANIFEST), srcManifestBytes)) {
    throw new Error("byte mismatch");
  }
});

await check("05 generated snapshot byte length is 83727", () => {
  const n = readBytes(DIST_SNAPSHOT).length;
  if (n !== EXPECTED_BYTE_LENGTH) throw new Error(`length ${n}`);
  return `${n} bytes`;
});

await check("06 generated snapshot SHA-256 matches", async () => {
  const got = await sha256Hex(readBytes(DIST_SNAPSHOT));
  if (got !== EXPECTED_SHA256) throw new Error(`sha256 ${got}`);
  return got;
});

await check("07 generated snapshot Git blob matches", async () => {
  const got = await gitBlobSha1Hex(readBytes(DIST_SNAPSHOT));
  if (got !== EXPECTED_GIT_BLOB) throw new Error(`git_blob ${got}`);
  return got;
});

await check("08 generated manifest validates (contract)", () => {
  manifest = assertRuntimeManifest(JSON.parse(readFileSync(DIST_MANIFEST, "utf8")));
});

await check("09 generated snapshot validates (shared contract)", () => {
  assertSnapshot(JSON.parse(readFileSync(DIST_SNAPSHOT, "utf8")));
});

await check("10 manifest identity matches generated snapshot", async () => {
  const bytes = readBytes(DIST_SNAPSHOT);
  assertManifestMatchesSnapshot(manifest, {
    id: APPROVED_SNAPSHOT_ID,
    byteLength: bytes.length,
    sha256: await sha256Hex(bytes),
    gitBlob: await gitBlobSha1Hex(bytes),
  });
  if (manifest.selected_snapshot.path !== snapshotPathForId(APPROVED_SNAPSHOT_ID)) {
    throw new Error("manifest path does not match id-derived route path");
  }
});

await check("11 source runtime snapshot == bundled fallback bytes", () => {
  if (!bytesEqual(srcSnapshotBytes, readBytes(SRC_FALLBACK))) {
    throw new Error("runtime snapshot differs from last-known-good fallback");
  }
});

await check("12 dist/_headers exists", () => {
  if (!existsSync(DIST_HEADERS)) throw new Error("missing dist/_headers");
});

await check("13 _headers contains exact manifest + snapshot rules", () => {
  const headers = readFileSync(DIST_HEADERS, "utf8");
  const manifestBlock = [
    "/public-surface-map/data/manifest.json",
    "  Content-Type: application/json; charset=utf-8",
    "  Cache-Control: no-cache, must-revalidate",
    "  X-Content-Type-Options: nosniff",
    "  X-Robots-Tag: noindex, nofollow, nosnippet",
  ].join("\n");
  const snapshotBlock = [
    "/public-surface-map/data/snapshots/*",
    "  Content-Type: application/json; charset=utf-8",
    "  Cache-Control: public, max-age=31536000, immutable",
    "  X-Content-Type-Options: nosniff",
    "  X-Robots-Tag: noindex, nofollow, nosnippet",
  ].join("\n");
  if (!headers.includes(manifestBlock)) throw new Error("manifest header block missing/altered");
  if (!headers.includes(snapshotBlock)) throw new Error("snapshot header block missing/altered");
  if (headers.indexOf(manifestBlock) > headers.indexOf(snapshotBlock)) {
    throw new Error("manifest exact rule must precede snapshot glob rule");
  }
});

await check("14 no external runtime URL in browser bundle", () => {
  const offenders = [];
  const forbidden = [
    "raw.githubusercontent.com",
    "githubusercontent.com",
    "objects.githubusercontent",
    "api.github.com",
  ];
  for (const file of clientJsFiles()) {
    const text = readFileSync(file, "utf8");
    for (const needle of forbidden) {
      if (text.includes(needle)) offenders.push(`${needle} in ${file}`);
    }
  }
  if (offenders.length) throw new Error(offenders.join("; "));
});

await check("15 Phase 1 interactive route exists", () => {
  if (!existsSync(DIST_INTERACTIVE)) throw new Error("missing interactive route");
});

await check("16 Phase 1 fallback table has 27 records", () => {
  const html = readFileSync(DIST_INTERACTIVE, "utf8");
  const snapshot = assertSnapshot(JSON.parse(readFileSync(SRC_FALLBACK, "utf8")));
  let present = 0;
  for (const node of snapshot.nodes) {
    // Each node renders its unique canonical URL in the no-JS fallback table.
    if (html.includes(node.canonical_public_url)) present += 1;
  }
  if (present !== 27) throw new Error(`found ${present} of 27 node records`);
  return "27 records";
});

await check("17 Phase 1 boundary statements remain", () => {
  const html = readFileSync(DIST_INTERACTIVE, "utf8");
  // The public interface carries FIVE persistent authority-boundary statements.
  // The bundled snapshot JSON supplies four of them; the fifth is a page-level
  // boundary statement not present in snapshot metadata. Require all five exact
  // literals in the generated Phase 1 HTML and fail closed on any miss. The
  // fifth is asserted explicitly here — it is NOT derived from snapshot data.
  const REQUIRED_HTML_BOUNDARY_STATEMENTS = [
    "Selected public surface only.",
    "Visual position does not indicate conceptual importance or internal authority.",
    "Reference routing does not establish a confirmed conceptual relation.",
    "Omission does not imply nonexistence.",
    "The public surface is not the internal Registry or a complete archive.",
  ];
  const missing = REQUIRED_HTML_BOUNDARY_STATEMENTS.filter((s) => !html.includes(s));
  if (missing.length) throw new Error(`missing: ${missing.join(" | ")}`);
  return `${REQUIRED_HTML_BOUNDARY_STATEMENTS.length} statements present`;
});

await check("18 Phase 2B runtime loader is same-origin, bounded, no storage/retry/telemetry", () => {
  // Phase 2B REQUIRES the browser bundle to reference the fixed same-origin
  // manifest route and snapshot prefix (the loader fetch targets). It must NOT
  // introduce off-origin data sources, arbitrary URLs, storage, retry/polling,
  // service workers, telemetry, or remote dynamic imports.
  const files = clientJsFiles();
  const combined = files.map((file) => readFileSync(file, "utf8")).join("\n");

  // (a) Required same-origin loader routes must be present.
  const required = [
    "/public-surface-map/data/manifest.json",
    "/public-surface-map/data/snapshots/",
  ];
  const missing = required.filter((needle) => !combined.includes(needle));
  if (missing.length) {
    throw new Error(`required same-origin loader route(s) missing: ${missing.join(", ")}`);
  }

  // (b) Forbidden runtime behaviors that Phase 2B must never introduce.
  //     `setTimeout` / `AbortController` remain allowed (bounded shared budget).
  const forbidden = [
    // off-origin data sources
    "raw.githubusercontent.com",
    "githubusercontent.com",
    "objects.githubusercontent",
    "api.github.com",
    // storage APIs
    "localStorage",
    "sessionStorage",
    "indexedDB",
    "document.cookie",
    // service worker
    "serviceWorker",
    // retry / polling
    "setInterval",
    // telemetry
    "sendBeacon",
    // remote dynamic import
    "import(",
  ];
  const offenders = [];
  for (const file of files) {
    const text = readFileSync(file, "utf8");
    for (const marker of forbidden) {
      if (text.includes(marker)) offenders.push(`${marker} in ${file}`);
    }
  }
  if (offenders.length) throw new Error(offenders.join("; "));
  return "same-origin manifest + snapshot routes present; no storage/retry/telemetry/off-origin";
});

for (const line of results) console.log(line);
console.log("");
if (failed > 0) {
  console.error(`verify-public-surface-map-build: ${failed} check(s) FAILED`);
  process.exit(1);
}
console.log(`verify-public-surface-map-build: all ${results.length} checks passed`);
